sys_script_include.script:
var api_tasker_task = Class.create();
api_tasker_task.prototype = {
    initialize: function() {
		this.api_dtech = new api_dtech_common();
		this.api_tasker_ui_component_data = new api_tasker_ui_component_data();
		this.taskerStatus = new TaskerStatus();
		this.requestTable = "x_153465_discovert_tasker_requests";
		this.titleField = "task_name";
    },

	acceptTask: function(task_sys_id) {
		var acceptResponse = {};
		acceptResponse.taskAccepted = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_task = new GlideRecord(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(task_sys_id)){
			new Task_uiAction().uiAction_AcceptAssignment(gr_task);
			acceptResponse.taskAccepted = true;
		}
		return acceptResponse;
	},

	assignTask: function(task_sys_id) {
		var assignResponse = {};
		assignResponse.taskAssigned = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_task = new GlideRecord(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(task_sys_id)){
			new Task_uiAction().uiAction_AssignTask(gr_task);
			assignResponse.taskAssigned = true;
		}
		return assignResponse;
	},

	changeTaskOrder: function(task_sys_id, newOrder){
		var changeOrder = {};
		changeOrder.taskActivated = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_task = new GlideRecord(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(task_sys_id)){
			gr_task.order = newOrder;
			gr_task.task_order = newOrder;
			gr_task.update();
			changeOrder.taskActivated = true;
		}
		return changeOrder;		
	},

	getAssignmentInformation: function(taskId){
		var lAssignmentInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lAssignmentInfo = this.api_tasker_ui_component_data.getAssignmentInformationGR(gr_task);
		}
		return lAssignmentInfo;
	},

	getDurationInformation: function(taskId){
		var lDurationInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lDurationInfo = this.api_tasker_ui_component_data.getDurationInformationGR(gr_task);
		}
		return lDurationInfo;
	},

	getItemMembersInformation: function(taskId){
		var lItemMembersInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lItemMembersInfo = this.api_tasker_ui_component_data.getItemMembersInformationGR(gr_task);
		}
		return lItemMembersInfo;
	},

	getItemMembersInformationTaskTree: function(taskId){
		var lItemMembersInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lItemMembersInfo = this.api_tasker_ui_component_data.getItemMembersInformationTaskTreeGR(gr_task);
		}
		return lItemMembersInfo;
	},	

	getOperationalInformation: function(taskId){
		var lOperationalInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lOperationalInfo = this.api_tasker_ui_component_data.getOperationalInformationGR(gr_task);
		}
		return lOperationalInfo;
	},

	// this only exists in task, so no reason to jump to common
	getResponseComments: function(taskId){
		var lResponseCommentsInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lResponseCommentsInfo = this.getResponseCommentsGR(gr_task);
		}
		return lResponseCommentsInfo;
	},

	// this is only on task, so the implementation is here
	getResponseCommentsGR: function(gr_task){
		var lResponseCommentsInfo = {};
		lResponseCommentsInfo.directive_reopen_comments = '';
		lResponseCommentsInfo.directive_response_comments = '';
		lResponseCommentsInfo.directive_reviewer_comments = '';
		lResponseCommentsInfo.directive_rework_comments = '';

		// View Comment on Detailed Status; added
		lResponseCommentsInfo.directive_content_comment = '';

		lResponseCommentsInfo.isResponseCommentsDirectiveShown = false;

		// use one var in ngIf for Response Comments Directive
		if (gr_task.getElement('comments_dt').getDisplayValue().length > 0 ||
			gr_task.getElement('response').getDisplayValue().length > 0 ||
			gr_task.getElement('reopen_comments').getDisplayValue().length > 0 ||
			gr_task.getElement('rework_comments').getDisplayValue().length > 0) {
			lResponseCommentsInfo.isResponseCommentsDirectiveShown = true;
			lResponseCommentsInfo.directive_reopen_comments = gr_task.getElement('reopen_comments').getDisplayValue();
			lResponseCommentsInfo.directive_response_comments = gr_task.getElement('response').getDisplayValue();
			lResponseCommentsInfo.directive_reviewer_comments = gr_task.getElement('comments_dt').getDisplayValue();
			lResponseCommentsInfo.directive_rework_comments = gr_task.getElement('rework_comments').getDisplayValue();
		}
		lResponseCommentsInfo.directive_work_item_type = gr_task.getElement('work_item_type').getDisplayValue();

		// 2.8.5 | 2023-07-07 | mmcc | STRY0137651 - When to Show Comments on Final Response Tab; added, get returns a string
		if (lResponseCommentsInfo.directive_work_item_type == 'review_item') {
			lResponseCommentsInfo.directive_content_comment = lResponseCommentsInfo.directive_reviewer_comments;
		} else {
			lResponseCommentsInfo.directive_content_comment = lResponseCommentsInfo.directive_response_comments;
		}
		return lResponseCommentsInfo;
	},

	// this only exists in task, so no reason to jump to common
	getStateInformation: function(taskId){
		var lStateInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lStateInfo = this.getStateInformationGR(gr_task);
		}
		return lStateInfo;
	},

	// this is only on task, so the implementation is here
	getStateInformationGR: function(gr_task){
		var lStateInfo = {};
		// NOTE: warning hours is actually a number of days, not hours
		// NOTE: calendar duration is Estimated Effort
		var arrStateFields = 
			["state", "u_wait_for_subtasks_to_finish", "tasker_type"];
		lStateInfo = this.api_dtech.loadObject(gr_task, arrStateFields);
		// add task id after loaded
		lStateInfo.taskId = gr_task.getUniqueValue();

		// Check the process flow
		lStateInfo.flow = this._createProcessFlow(lStateInfo);

		return lStateInfo;
	},

	getSubTasksInformation: function(taskId){
		var lSubTasksInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lSubTasksInfo = this.api_tasker_ui_component_data.getSubTasksInformationGR(gr_task);
		}
		return lSubTasksInfo;
	},

	getSubTasksInformationWithList: function(taskId){
		var lSubTasksInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lSubTasksInfo = this.api_tasker_ui_component_data.getSubTasksInformationWithListGR(gr_task);
		}
		return lSubTasksInfo;
	},

	getTaskerFilesInformation: function(taskId){
		var lTaskerFilesInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lTaskerFilesInfo = this.api_tasker_ui_component_data.getTaskerFilesInformationGR(gr_task);
		}
		return lTaskerFilesInfo;
	},

	getTaskerFilesInformationWithFiles: function(taskId){
		var lTaskerFilesInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lTaskerFilesInfo = this.api_tasker_ui_component_data.getTaskerFilesInformationWithFilesGR(gr_task);
		}
		return lTaskerFilesInfo;
	},

	getTaskTreeInformation: function(taskId){
		var lTaskTreeInfo = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			lTaskTreeInfo = this.getTaskTreeInformationGR(gr_task);
		}
		return lDurationInfo;
	},

	getTaskTreeInformationGR: function(gr_task){
		var lTaskTreeInfo = {};
		// NOTE: warning hours is actually a number of days, not hours
		// NOTE: calendar duration is Estimated Effort
		var arrStateFields = 
			["u_task_tree"];
		lTaskTreeInfo = this.api_dtech.loadObject(gr_task, arrStateFields);
		// add task id after loaded
		lTaskTreeInfo.taskId = gr_task.getUniqueValue();
		return lTaskTreeInfo;
	},

	getUIActionParamaters: function(taskId, action_name, action_sys_id){
		var params = {};
		var gr_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(taskId)){
			params = this.getUIActionParamatersGR(gr_task, action_name, action_sys_id);
		}
		return params;
	},

	getUIActionParamatersGR: function(gr_task, action_name, action_sys_id){
		var params = {};
		var objTaskActions = this._get_ui_actions_icons();
		var arrItem = Object.keys(objTaskActions).filter(function(key){
			return objTaskActions[key].action_name==action_name || key==action_sys_id;});
		if(arrItem[0]){
			// get the key b/c the sys_id is the key of the array
			var ui_action_sys_id = arrItem[0];
			// load ui action parameters
			params = this._get_ui_actions_params(gr_task, ui_action_sys_id);
		}
		return params;
	},

	publishTask: function(task_sys_id) {
		var publishResponse = {};
		publishResponse.taskPublished = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_task = new GlideRecord(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(task_sys_id)){
			new Task_uiAction().uiAction_PublishDraftTasks(gr_task, 'taskOnly');
			publishResponse.taskPublished = true;
		}
		return publishResponse;
	},

	startTask: function(task_sys_id) {
		var startResponse = {};
		startResponse.taskStarted = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_task = new GlideRecord(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if(gr_task.get(task_sys_id)){
			new Task_uiAction().uiAction_StartWork(gr_task);
			startResponse.taskStarted = true;
		}
		return startResponse;
	},

	// Check the process flow
	_createProcessFlow: function(stateInformationObject) {
		// STRY0146507 - Certification Support- Placeholder
		//Note: GlideRecordSecure is not feasible to use on this widget that is reading values from a table enable by the process flow plugin
		var gf = new GlideRecord('sys_process_flow'); 
		gf.addActiveQuery();
		gf.addQuery('table', api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		if (!stateInformationObject.u_wait_for_subtasks_to_finish || stateInformationObject.u_wait_for_subtasks_to_finish.value != false)
			gf.addQuery('label', '!=', 'Wait for subtasks');
		gf.addQuery('description', 'CONTAINS', stateInformationObject.tasker_type.display_value);
		gf.orderBy('order');
		gf.query();

		var items = [];
		while (gf.next()) {
			var item = {};
			item.name = gf.label.toString();
			item.colour = item.name;
			items.push(item);
		}
		// set the highest number to a success color
		if(items.length>0){
			items[items.length-1].colour = 'success';
		}

		return items;
	},

	getParentTaskFields: function(gr_task, arrParentTaskFields){
		var parentTaskId = gr_task.getValue("parent");
		var gr_parent_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		var lParentTasklInfo;
		if(gr_parent_task.get(parentTaskId)){
			lParentTasklInfo = this.api_dtech.loadObject(gr_parent_task, arrParentTaskFields);
		}
		return lParentTasklInfo;
	},

	_getTopTaskFields: function(gr_task, arrTopTaskFields){
		var topTaskId = gr_task.getValue("u_top_task");
		var gr_top_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		var lTopTasklInfo;
		if(gr_top_task.get(topTaskId)){
			lTopTasklInfo = this.api_dtech.loadObject(gr_task, arrTopTaskFields);
		}
		return lTopTasklInfo;
	},

	// this returns an object with just the id, but could return more data later
	// NOTE: to allow multiple requests, we would need to update this
	_get_task_request: function(task_id, requestType, status){	
		var requestInfo = {};

		var gr = new GlideRecordSecure(this.requestTable);
		gr.addQuery('parent', task_id);
		gr.addQuery('u_request_type', requestType);
		gr.addQuery('u_status', status);
		gr.query();

		while(gr.next()){
			requestInfo.request_sys_id = gr.getUniqueValue();
		}
		return requestInfo;
	},

	// **************************************************************************************************
	// START - Context Menu Sectioin
	// **************************************************************************************************
	// NOTE: not sure if we want to burry this in code but, this would be how we would add the separators
	_get_ui_actions_context_menu_array: function(){
		var arrActions = [
			'18b25020db9a5890dd3d6165ca961972', // "name": "Publish Task(s)", "action_name" : "publish_tasks"
			'0187ab004f181b00303dc3818110c764', // "name": "Start Work" "action_name": "workInProgress"
			'f97729461b96ccd0358efd16dc4bcb9e', // "name": "Request Clarification" "action_name": "openModalRequestClarificationSP"
			'66635c24db685850dd3d6165ca9619aa', // "name": "Respond Clarification", "action_name": "openModalRespondClarificationSP"
			'ded97a314fec5700303dc3818110c7a5', // "name": "Request Extension", "action_name": "openModalRequestExtensionSP"
			'a8217df7db94d450dd3d6165ca961907', // "name": "Respond Extension Request", "action_name": "openModalRespondExtensionSP"
			'403b714edbb017003a8d6be3ca961961', // "name": "Assign Task" "action_name": "assigned"
			'7703adb74f88d700303dc3818110c784', // "name": "Accept Assignment" "action_name": "AcceptAssignment"
			'268da9334fc8d700303dc3818110c72a', // "name": "Reject Assignment" "action_name": "rejectAssignment"
			'caf24e87dbeda700c18c59b2ca9619f1', // "name": "Reject Task for Primary Assignee" "action_name": "rejectOUAssignment"
			'531dde924f68d700303dc3818110c704', // "name": "Request Reassignment", "action_name": "openModalRequestReassignmentSP"
			'c6e6e812dbd09050dd3d6165ca961990', // "name": "Respond Reassignment", "action_name": "openModalRespondReassignmentSP"
			'3d8be97cdb58e410936dd498f496197a', // "name": "Send to Review" "action_name": "inReview"
			'separator', // add a separator
			'c898f2fbdb41a3c8c18c59b2ca9619e0', // "name": "Abstain", "action_name": "Abstain-SendToReview"
			'ba139a01db732f00c18c59b2ca96193f', // "name": "Approve", "action_name": "Approve-SendToReview"
			'ef909466db11e300c18c59b2ca96198e', // "name": "Approve & Sign", "action_name": "ApproveSign-SendToReview"
			'77477677db41a3c8c18c59b2ca961932', // "name": "Concur", "action_name": "Concur-SendToReview"
			'2b0abab7db81a3c8c18c59b2ca961992', // "name": "Concur & sign" "action_name": "ConcurSign-SendToReview"
			'6ca12aa7db052f88c18c59b2ca96192a', // name: "Reject", "action_name": "Reject-Approval"
			'3469ab804f181b00303dc3818110c77f', // "name": "Send to Review", "action_name": "inReview"
			'fbe927c04f181b00303dc3818110c7f5', // "name": "Mark Complete" "action_name": "ClosedComplete"
			'7e48f6f7db41a3c8c18c59b2ca961900', // "name": "NonConcur", "action_name": "NonConcur-SendToReview"
			'5bb706e5dba33b40c448d1c2ca961983', // "name": "Nonconcur & sign" "action_name": "NonconcurSign-SendToReview"
			'd237f7974fa28300303dc3818110c7c4', // "name": "Reopen Task", "action_name": "Reopen"
			'baa96f804f181b00303dc3818110c74e', // "name": "Send to Rework" "action_name": "rework"
			//'separator', // add a separator
			//'addRequestAccessGuidhere', // "name": "Request Access for Member(s)"  - no guid today
			'separator', // add a separator
			'9e53d1f8db02f01087f2892d139619ed' // "name": "Delete", (task) , "action_name" : "delete_tasks"
		];
		return arrActions;
	},

	_get_ui_actions_params: function(gr_task, action_sys_id){
		var params = {};
		params.task_sys_id = gr_task.getUniqueValue();
		var requestInfo = {};
		switch (action_sys_id){
			case '9e53d1f8db02f01087f2892d139619ed': // "name": "Delete", (task), "action_name" : "delete_tasks"
				params.action_name = "delete_tasks";
				params.number_name = gr_task.getDisplayValue("taskernumber") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Delete') + ' ' + params.number_name + '?';
				break;
			case '18b25020db9a5890dd3d6165ca961972': // "name": "Publish Task(s)", "action_name" : "publish_tasks"
				params.action_name = "publish_tasks";
				// making these objects allows us to just load fields in the ui action function
				params.state = gr_task.getValue("state");
				params.calchaschildren = gr_task.getValue("calchaschildren");
				params.number_name = gr_task.getDisplayValue("taskernumber") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Tasker - Title - Publish Selection for') + params.number_name;
				break;
			case '6ca12aa7db052f88c18c59b2ca96192a': // name: "Reject", "action_name": "Reject-Approval"
				params.action_name = "Reject-Approval";
				params.comments_dt = gr_task.getDisplayValue('comments_dt');
				if(!params.comments_dt || params.comments_dt==null){
					params.comments_dt = '';
				}
				params.number_name = gr_task.getDisplayValue("taskernumber") + ': ' + gr_task.getValue('short_description');
				params.title = params.number_name + '?';
				// this is tasker_type value
				var taskType = gr_task.getDisplayValue("tasker_type.u_value");
				var taskerTypesConstants = new TaskerTypes().getValueConstants();
				if (taskType == taskerTypesConstants.approval_with_signature){
					params.title = gs.getMessage('Tasker - Title - Rejection for Approval with Signature') + ' ' + params.number_name + '?';
				} else if (taskType == taskerTypesConstants.approval) {
					params.title = gs.getMessage('Tasker - Title - Rejection for Approval without Signature') + ' ' + params.number_name + '?';
				}
				break;
			case 'd237f7974fa28300303dc3818110c7c4': // "name": "Reopen Task", "action_name": "Reopen"
				params.action_name = "Reopen";
				params.active = gr_task.getDisplayValue('active');
				params.number = gr_task.getValue('number');
				params.number_name = gr_task.getDisplayValue("taskernumber") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Tasker - Title - Reopen Selection for') + params.number_name;
				// initialize parent fields
				params.parent_sys_id = '';
				params.parent_active = '';
				params.parent_number = '';

				if (!gr_task.parent.nil()){
					var arrParentTaskFields = ["sys_id", "active", "number"];
					var lParentTasklInfo = this.getParentTaskFields(gr_task, arrParentTaskFields);
					params.parentInfo = lParentTasklInfo;

					// parent logic - also in Business Rule Tasker - Tasker - onLoad - set max routes
					// if we do api call back in the UI Script, could remove from initial load
					params.parent_sys_id = lParentTasklInfo["sys_id"].value;
					params.parent_active = lParentTasklInfo["active"].display_value;
					params.parent_number = lParentTasklInfo["number"].value;

					var url = this._get_URL_for_Task_Based_on_Prefrences(params.parent_sys_id,'sp');
					url = url + '&state=3&order=1';
					params.reopenParentMsg = " <b>" + 
						gs.getMessage('Tasker - Reopen Parent is not active - start') + 
						" " + '<a href=' + url + '>' + params.parent_number + '</a>' + 
						' ' + gs.getMessage('Tasker - Reopen Parent is not active - end') + '</b>';
				}
				// reopen logic - also in Business Rule Tasker - Tasker - onLoad - set max routes
				// if we do api call back in the UI Script, could remove from initial load
				params.closed_to_long_to_reopen = false;
				params.ReopenMaxDays = gs.getProperty('x_153465_discovert.ReopenMaxDays');
				params.closed_at = gr_task.closed_at;
				var closedAt = new GlideDateTime(params.closed_at);
				// STRY0102134 - Apply Default Schedule to Task Information
				var maxReopenDate;
				if(!gr_task.active){
					var today = new GlideDateTime().getNumericValue();
					// find the end date in the schedule
					var tdc = new TaskerDurationCalculator();
					maxReopenDate = 
						tdc.calculateDateOfAddedBusinessDays(null, params.ReopenMaxDays, closedAt);
					params.closed_to_long_to_reopen = 
						(today > new GlideDateTime(maxReopenDate).getNumericValue());
				}
				params.closeTooLongMsg = params.number + ' ' + 
					gs.getMessage('Tasker - Closed too long to reopen 1') + ' ' + 
					params.ReopenMaxDays + ' ' + 
					gs.getMessage('Tasker - Closed too long to reopen 2') + ' ' + 
					params.closed_at + gs.getMessage('Tasker - Closed too long to reopen 3');

				break;
			case 'c898f2fbdb41a3c8c18c59b2ca9619e0': // "name": "Abstain", "action_name": "Abstain-SendToReview"
			case 'ba139a01db732f00c18c59b2ca96193f': // "name": "Approve", "action_name": "Approve-SendToReview"
			case '77477677db41a3c8c18c59b2ca961932': // "name": "Concur", "action_name": "Concur-SendToReview"
			case '7e48f6f7db41a3c8c18c59b2ca961900': // "name": "NonConcur", "action_name": "NonConcur-SendToReview"
				// the common settings are grouped at the top and another case is below for the differences
				params.table = api_dtech_common.CONST_DTECH_TASK_TABLE_NAME;
				params.number = gr_task.getValue('number');
				params.placeHolderText = gs.getMessage('Tasker - Please enter Additional Comments');
				params.reviewer_comments = gr_task.getDisplayValue('comments_dt');
				if(!params.reviewer_comments || params.reviewer_comments==null){
					params.reviewer_comments = '';
				}
				params.reviewCommentsRequired = true;
				params.shared = { 
					fields: {
						comments_dt: {
							value: params.reviewer_comments,
							displayValue: params.reviewer_comments,
							sys_mandatory: true,
							mandatory: true,
							placeholder: params.placeHolderText,
							readonly: false
						}
					}
				};

				// the actions in this block are the same with the exception of the view and the title
				// so, added a second switch case to make more concise
				switch (action_sys_id){
					case 'c898f2fbdb41a3c8c18c59b2ca9619e0': // "name": "Abstain", "action_name": "Abstain-SendToReview"
						params.action_name = "Abstain-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Abstain') + ' ' + params.number;
						params.view = 'Abstain_Response';
						break;
					case 'ba139a01db732f00c18c59b2ca96193f': // "name": "Approve", "action_name": "Approve-SendToReview"
						params.action_name = "Approve-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Approve') + ' ' + params.number;
						params.view = 'Accept_Response';
						break;
					case '77477677db41a3c8c18c59b2ca961932': // "name": "Concur", "action_name": "Concur-SendToReview"
						params.action_name = "Concur-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Concur') + ' ' + params.number;
						params.view = 'Accept_Response';
						break;

					case '7e48f6f7db41a3c8c18c59b2ca961900': // "name": "NonConcur", "action_name": "NonConcur-SendToReview"
						params.action_name = "NonConcur-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Nonconcur') + ' ' + params.number;
						params.view = 'Reject_Response';
						break;						
				}

				break;
			case 'ef909466db11e300c18c59b2ca96198e': // "name": "Approve & Sign", "action_name": "ApproveSign-SendToReview"
			case '2b0abab7db81a3c8c18c59b2ca961992': // "name": "Concur & sign" "action_name": "ConcurSign-SendToReview"
			case '5bb706e5dba33b40c448d1c2ca961983': // "name": "Nonconcur & sign" "action_name": "NonconcurSign-SendToReview"
				params.table = api_dtech_common.CONST_DTECH_TASK_TABLE_NAME;
				params.number = gr_task.getValue('number');
				params.placeHolderText = gs.getMessage('Tasker - Please enter Additional Comments');
				params.u_signature_instructions = gr_task.getDisplayValue('u_signature_instructions');
				if(!params.u_signature_instructions || params.u_signature_instructions==null){
					params.u_signature_instructions = '';
				}
				params.review_sign_comments = gr_task.getValue('comments_dt');
				if(!params.review_sign_comments || params.review_sign_comments==null){
					params.review_sign_comments = '';
				}

				// STRY0120264
				params.isSignChecked = gr_task.getValue('u_reviewer_signed');
				params.shared = {
					fields: {
						u_signature_instructions: {
							value: params.u_signature_instructions,
							displayValue: params.u_signature_instructions, 
							sys_mandatory: true, 
							mandatory: true, 
							placeholder: params.placeHolderText},
						// STRY0120264
						u_reviewer_signed: {value: params.isSignChecked, sys_mandatory: true, mandatory: true},
						comments_dt: {
							value: params.review_sign_comments, 
							displayValue: params.review_sign_comments, 
							sys_mandatory: true, 
							mandatory: true}						
					}
				};

				// the actions in this block are the same with the exception of the view and the title
				// so, added a second switch case to make more concise
				switch (action_sys_id){
					case 'ef909466db11e300c18c59b2ca96198e': // "name": "Approve & Sign", "action_name": "ApproveSign-SendToReview"
						params.action_name = "ApproveSign-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Approve & sign Acknowledgement for') + params.number;
						params.view = 'Confirm_Signature_Instructions';
						break;
					case '2b0abab7db81a3c8c18c59b2ca961992': // "name": "Concur & sign" "action_name": "ConcurSign-SendToReview"
						params.action_name = "ConcurSign-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Concur & sign') + ' ' + params.number;
						params.view = 'Confirm_Signature_Instructions';
						break;
					case '5bb706e5dba33b40c448d1c2ca961983': // "name": "Nonconcur & sign" "action_name": "NonconcurSign-SendToReview"
						params.action_name = "NonconcurSign-SendToReview";
						params.title = gs.getMessage('Tasker - Title - Nonconcur & sign') + ' ' + params.number;
						params.view = 'Reject_Signature_Instructions';
						break;
				}


				break;
			case '268da9334fc8d700303dc3818110c72a': // "name": "Reject Assignment" "action_name": "rejectAssignment"
			case 'caf24e87dbeda700c18c59b2ca9619f1': // "name": "Reject Task for Primary Assignee" "action_name": "rejectOUAssignment"
				params.table = api_dtech_common.CONST_DTECH_TASK_TABLE_NAME;
				params.number = gr_task.getValue('number');

				params.isPreCompleteShown = false;
				if (action_sys_id=='268da9334fc8d700303dc3818110c72a'){ // "name": "Reject Assignment" "action_name": "rejectAssignment"
					params.action_name = "rejectAssignment";
					params.title = gs.getMessage('Tasker - Title - Reject Assignment') + ' ' + params.number;
				} else if(action_sys_id == 'caf24e87dbeda700c18c59b2ca9619f1'){ // "name": "Reject Task for Primary Assignee" "action_name": "rejectOUAssignment"
					params.action_name = "rejectOUAssignment";
					params.title = gs.getMessage('Tasker - Title - Reject Primary Assignee for Task') + ' ' + params.number;
				}
				params.placeHolderText = gs.getMessage('Tasker - Please enter Additional Comments');
				params.comments = gr_task.getValue('comments');
				if(!params.comments || params.comments==null){
					params.comments = '';
				}
				params.view = 'Additional_Comments_Modal';
				params.shared = { 
					fields: {
						comments: {
							value: params.comments, 
							displayValue: params.comments, 
							sys_mandatory: true, 
							mandatory: true, 
							placeholder: params.placeHolderText}
					}
				};


				break;
			case '3469ab804f181b00303dc3818110c77f': // "name": "Send to Review", "action_name": "inReview"
				params.table = api_dtech_common.CONST_DTECH_TASK_TABLE_NAME;
				params.number = gr_task.getValue('number');
				params.action_name = "inReview";
				params.isPreCompleteShown = false;

				params.title = gs.getMessage('Tasker - Title - Send to Review for Task') + ' ' + params.number;
				params.placeHolderText = gs.getMessage('Tasker - Please enter Response Comments');
				params.view = 'Send_to_Review';
				params.response_comments = gr_task.getValue('response');
				if(!params.response_comments || params.response_comments==null){
					params.response_comments = '';
				}
				params.rework_comments = gr_task.getValue('rework_comments');
				if(!params.rework_comments || params.rework_comments==null){
					params.rework_comments = '';
				}
				params.provide_response = gr_task.getValue('provide_response');
				params.shared = { 
					fields: {
						response: {
							value: params.response_comments, 
							displayValue: params.response_comments, 
							sys_mandatory: true, 
							mandatory: true, 
							placeholder: params.placeHolderText, readonly: false},
						rework_comments: {
							value: params.rework_comments, displayValue: params.rework_comments, sys_mandatory: false, mandatory: false},
						provide_response: {
							value: params.provide_response, sys_mandatory: true, mandatory: true}
					}
				};
				break;
			case 'baa96f804f181b00303dc3818110c74e': // "name": "Send to Rework" "action_name": "rework"
				params.table = api_dtech_common.CONST_DTECH_TASK_TABLE_NAME;
				params.number = gr_task.getValue('number');
				params.action_name = "rework";
				params.isPreCompleteShown = false;
				params.title = gs.getMessage('Tasker - Title - Send to Rework') + ' ' + params.number;
				params.placeHolderText = gs.getMessage('Tasker - Please enter Rework Comments');
				params.view = 'Send_to_Rework';
				params.response_comments = gr_task.getValue('response');
				if(!params.response_comments || params.response_comments==null){
					params.response_comments = '';
				}
				params.rework_comments = gr_task.getValue('rework_comments');
				if(!params.rework_comments || params.rework_comments==null){
					params.rework_comments = '';
				}
				params.shared = { 
					fields: {
						response: {value: params.response_comments, displayValue: params.response_comments, sys_mandatory: false, mandatory: false},
						rework_comments: {value: params.rework_comments, displayValue: params.rework_comments, sys_mandatory: true, mandatory: true, placeholder: params.placeHolderText}
					}
				};
				break;
			case 'fbe927c04f181b00303dc3818110c7f5': // "name": "Mark Complete" "action_name": "ClosedComplete"
				params.table = api_dtech_common.CONST_DTECH_TASK_TABLE_NAME;
				params.number = gr_task.getValue('number');
				params.action_name = "ClosedComplete";

				// any user will use this button to close the task
				params.title = gs.getMessage('Tasker - Title - Mark Complete for Task') + ' ' + params.number;
				params.placeHolderText = gs.getMessage('Tasker - Please enter Review Comments');
				params.view = 'Reviewer_Complete';
				var reviewerCommentsMandatory = (gr_task.getValue('state') == "14");
				var responseCommentsMandatory = !reviewerCommentsMandatory;
				params.response_comments = gr_task.getValue('response');
				if(!params.response_comments || params.response_comments==null){
					params.response_comments = '';
				}
				params.reviewer_comments = gr_task.getValue('comments_dt');
				if(!params.reviewer_comments || params.reviewer_comments==null){
					params.reviewer_comments = '';
				}
				params.rework_comments = gr_task.getValue('rework_comments');
				if(!params.rework_comments || params.rework_comments==null){
					params.rework_comments = '';
				}
				params.shared = { 
					fields: {
						response: {value: params.response_comments, displayValue: params.response_comments, sys_mandatory: false, mandatory: responseCommentsMandatory},
						rework_comments: {value: params.rework_comments, displayValue: params.rework_comments, sys_mandatory: false, mandatory: false},
						comments_dt: {value: params.reviewer_comments, displayValue: params.reviewer_comments, sys_mandatory: reviewerCommentsMandatory, mandatory: reviewerCommentsMandatory}
					}
				};

				break;
			case 'f97729461b96ccd0358efd16dc4bcb9e': // "name": "Request Clarification" "action_name": "openModalRequestClarificationSP"
				params.table = this.requestTable;
				params.action_name = "openModalRequestClarificationSP";
				params.request_sys_id = -1;
				params.title = gs.getMessage('Tasker - Title - Request Clarification');
				params.view = 'requesttop';
				params.isRequest = true;
				params.request_type = 'Clarification';
				params.parent = params.task_sys_id;
				break;
			case '66635c24db685850dd3d6165ca9619aa': // "name": "Respond Clarification", "action_name": "openModalRespondClarificationSP"
				params.table = this.requestTable;
				params.action_name = "openModalRespondClarificationSP";
				params.title = gs.getMessage('Tasker - Title - Respond Clarification Request');
				params.view = 'responsetop';
				params.isRequest = false;
				params.request_type = 'Clarification';
				params.parent = '';
				requestInfo = this._get_task_request(params.task_sys_id, params.request_type, "In Progress");
				params.request_sys_id = requestInfo.request_sys_id;
				break;
			case 'ded97a314fec5700303dc3818110c7a5': // "name": "Request Extension", "action_name": "openModalRequestExtensionSP"
				params.table = this.requestTable;
				params.action_name = "openModalRequestExtensionSP";
				params.request_sys_id = -1;
				params.title = gs.getMessage('Tasker - Title - Request Extension');
				params.view = 'requesttop';
				params.isRequest = true;
				params.request_type = 'Extension';
				params.parent = params.task_sys_id;
				break; 
			case 'a8217df7db94d450dd3d6165ca961907': // "name": "Respond Extension Request", "action_name": "openModalRespondExtensionSP"
				params.table = this.requestTable;
				params.action_name = "openModalRespondExtensionSP";
				params.title = gs.getMessage('Tasker - Title - Respond Extension Request');
				params.view = 'responsetop';
				params.isRequest = false;
				params.request_type = 'Extension';
				params.parent = '';
				requestInfo = this._get_task_request(params.task_sys_id, params.request_type, "In Progress");
				params.request_sys_id = requestInfo.request_sys_id;
				break;
			case '531dde924f68d700303dc3818110c704': // "name": "Request Reassignment", "action_name": "openModalRequestReassignmentSP"
				params.table = this.requestTable;
				params.action_name = "openModalRequestReassignmentSP";
				params.request_sys_id = -1;
				params.title = gs.getMessage('Tasker - Title - Request Reassignment');
				params.view = 'requesttop';
				params.isRequest = true;
				params.request_type = 'Reassignment';
				params.parent = params.task_sys_id;
				break;
			case 'c6e6e812dbd09050dd3d6165ca961990': // "name": "Respond Reassignment", "action_name": "openModalRespondReassignmentSP"
				params.table = this.requestTable;
				params.action_name = "openModalRespondReassignmentSP";
				params.title = gs.getMessage('Tasker - Title - Respond Reassignment Request');
				params.view = 'responsetop';
				params.isRequest = false;
				params.request_type = 'Reassignment';
				params.parent = '';
				requestInfo = this._get_task_request(params.task_sys_id, params.request_type, "In Progress");
				params.request_sys_id = requestInfo.request_sys_id;
				break;
			case '0187ab004f181b00303dc3818110c764': // "name": "Start Work" "action_name": "workInProgress"
				params.action_name = "workInProgress";
				break;
			case '403b714edbb017003a8d6be3ca961961': // "name": "Assign Task" "action_name": "assigned"
				params.action_name = "assigned";
				break;
			case '7703adb74f88d700303dc3818110c784': // "name": "Accept Assignment" "action_name": "AcceptAssignment"
				params.action_name = "AcceptAssignment";
				break;
			//case 'addRequestAccessGuidhere': // "name": "Request Access for Member(s)"  - no guid today
			//	break;
			default:
				var errMsg = "Tasker - function: _get_ui_actions_params - an action was requested that isn't implemented.  UI Action sys_id: " + action_sys_id;
				gs.addErrorMessage(errMsg);
				break;
		}
		return params;

	},

