	_get_URL_for_Task_Based_on_Prefrences: function(sys_id, current_view){
		var oUserPref = new tasker_User_Form_Preferences();
		var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(sys_id,current_view);

		var task_url;
		task_url =  
			'../' + url_Properties.portal_url_ref + 
			'?id=' + url_Properties.pageId + 
			'&table=' + api_dtech_common.CONST_DTECH_TASK_TABLE_NAME + 
			'&sys_id=' + sys_id +
			'&view=' + url_Properties.view;

		return task_url;
	},	

    type: 'api_tasker_task'
};
